import { PrismaClient } from '@prisma/client';
import { RedisClient } from 'redis';
import { Kafka } from 'kafkajs';

const prisma = new PrismaClient();
const redisClient = new RedisClient();
const kafka = new Kafka({ clientId: 'identity-service', brokers: ['kafka-broker:9092'] });

async function validateUser(username: string, password: string): Promise<boolean> {
    // Validate inputs
    if (!username || !password) {
        throw new Error('Username and password are required');
    }

    // Check Redis cache first
    const cachedUser = await getCachedUser(username);
    if (cachedUser) {
        return cachedUser.password === password; // Simplified for demonstration
    }

    // Fetch user from database
    const user = await prisma.user.findUnique({
        where: { username },
    });

    if (!user) {
        return false;
    }

    // Validate password (simplified for demonstration)
    const isValidPassword = user.password === password; // Replace with proper hashing check

    // Cache the user if valid
    if (isValidPassword) {
        cacheUser(username, user.password);
    }

    return isValidPassword;
}

async function getCachedUser(username: string): Promise<any> {
    return new Promise((resolve, reject) => {
        redisClient.get(username, (err, result) => {
            if (err) {
                return reject(err);
            }
            resolve(result ? JSON.parse(result) : null);
        });
    });
}

function cacheUser(username: string, password: string): void {
    redisClient.set(username, JSON.stringify({ username, password }), 'EX', 3600); // Cache for 1 hour
}

// Kafka producer example
async function sendUserValidationEvent(username: string, isValid: boolean): Promise<void> {
    const producer = kafka.producer();
    await producer.connect();
    await producer.send({
        topic: 'user-validation',
        messages: [{ value: JSON.stringify({ username, isValid }) }],
    });
    await producer.disconnect();
}

// Example usage
(async () => {
    try {
        const isValid = await validateUser('testUser', 'testPassword');
        await sendUserValidationEvent('testUser', isValid);
        console.log(`User validation result: ${isValid}`);
    } catch (error) {
        console.error('Error validating user:', error);
    }
})();
